CREATE OR REPLACE FUNCTION fpb_ktm_get_atm_contact_no (as_reqno char) RETURNS bigint AS $body$
DECLARE

li_count integer;
ls_conno sc_lon_m_contract.loan_contract_no%type;

BEGIN

    select loan_contract_no into STRICT ls_conno
    from  sc_lon_m_loan_history
    where loan_requestment_no = as_reqno
    and   loan_type = '9'
    and   clear_target = '1'
    and   principal_balance_of_loan > 0;

    if coalesce(ls_conno::text, '') = '' then ls_conno := '0';end if;

    return ls_conno;
  exception when others then return '0';

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
